// ===== Class stubs =====

export class TFile {
	path = '';
	name = '';
	basename = '';
	extension = 'md';
	parent: TFolder | null = null;
	stat = { ctime: 0, mtime: 0, size: 0 };
}

export class TFolder {
	path = '';
	name = '';
	parent: TFolder | null = null;
	children: Array<TFile | TFolder> = [];
	isRoot(): boolean {
		return this.parent === null;
	}
}

export class TAbstractFile {
	path = '';
	name = '';
}

export class Component {
	private _children: Component[] = [];
	private _events: Array<{ off: () => void }> = [];
	private _intervals: number[] = [];
	addChild<T extends Component>(child: T): T {
		this._children.push(child);
		return child;
	}
	removeChild<T extends Component>(child: T): T {
		this._children = this._children.filter((c) => c !== child);
		return child;
	}
	register(cb: () => void): void {
		this._events.push({ off: cb });
	}
	registerEvent(ref: { off?: () => void } | unknown): void {
		if (ref && typeof (ref as { off?: () => void }).off === 'function') {
			this._events.push(ref as { off: () => void });
		}
	}
	registerInterval(id: number): number {
		this._intervals.push(id);
		return id;
	}
	registerDomEvent(): void {
		// no-op for tests
	}
	load(): void {
		this.onload?.();
	}
	unload(): void {
		this.onunload?.();
		for (const e of this._events) e.off();
		for (const i of this._intervals) clearInterval(i);
		for (const c of this._children) c.unload();
		this._events = [];
		this._intervals = [];
		this._children = [];
	}
	onload?(): void;
	onunload?(): void;
}

export class Events {
	private listeners = new Map<string, Set<(...data: unknown[]) => unknown>>();
	on(name: string, cb: (...data: unknown[]) => unknown): { off: () => void } {
		let set = this.listeners.get(name);
		if (!set) {
			set = new Set();
			this.listeners.set(name, set);
		}
		set.add(cb);
		return { off: () => set!.delete(cb) };
	}
	off(name: string, cb: (...data: unknown[]) => unknown): void {
		this.listeners.get(name)?.delete(cb);
	}
	trigger(name: string, ...data: unknown[]): void {
		this.listeners.get(name)?.forEach((cb) => cb(...data));
	}
}

export class Notice {
	message = '';
	constructor(msg = '', _timeout = 0) {
		this.message = msg;
	}
	setMessage(msg: string): this {
		this.message = msg;
		return this;
	}
	hide(): void {
		// no-op
	}
}

export interface MenuItem {
	title: string;
	icon: string | undefined;
	submenu: Menu | null;
	onClickCb: (() => void) | undefined;
	setTitle(t: string): MenuItem;
	setIcon(i: string): MenuItem;
	onClick(cb: () => void): MenuItem;
	setSubmenu(): Menu;
}

export class Menu {
	items: Array<{ title: string; icon?: string; submenu?: Menu | null; onClick?: () => void }> = [];
	addItem(cb: (item: MenuItem) => void): this {
		const wrapper: MenuItem = {
			title: '',
			icon: undefined,
			submenu: null,
			onClickCb: undefined,
			setTitle(t: string) {
				this.title = t;
				return this;
			},
			setIcon(i: string) {
				this.icon = i;
				return this;
			},
			onClick(c: () => void) {
				this.onClickCb = c;
				return this;
			},
			setSubmenu() {
				this.submenu = new Menu();
				return this.submenu;
			},
		};
		cb(wrapper);
		this.items.push({
			title: wrapper.title,
			icon: wrapper.icon,
			submenu: wrapper.submenu,
			onClick: wrapper.onClickCb,
		});
		return this;
	}
	addSeparator(): this {
		this.items.push({ title: '---' });
		return this;
	}
	showAtPosition(_pos: { x: number; y: number }): this {
		return this;
	}
	showAtMouseEvent(_e: MouseEvent): this {
		return this;
	}
}

export class Modal {
	contentEl: HTMLElement;
	app: App;
	private opened = false;
	constructor(app: App) {
		this.app = app;
		this.contentEl = makeEl();
	}
	open(): void {
		this.opened = true;
		this.onOpen?.();
	}
	close(): void {
		this.opened = false;
		this.onClose?.();
	}
	onOpen?(): void;
	onClose?(): void;
}

