export interface CachedMetadata {
	frontmatter?: Record<string, unknown>;
	tags?: Array<{ tag: string; position?: unknown }>;
}

export interface App {
	vault: Vault;
	metadataCache: MetadataCache;
	fileManager: FileManager;
	workspace: Workspace;
}

export interface Vault {
	configDir: string;
	getFiles(): TFile[];
	getMarkdownFiles(): TFile[];
	getFileByPath(path: string): TFile | null;
	getAbstractFileByPath(path: string): TFile | TFolder | null;
	getAllFolders(includeRoot?: boolean): TFolder[];
	read(file: TFile): Promise<string>;
	modify(file: TFile, content: string): Promise<void>;
	create(path: string, content: string): Promise<TFile>;
	process(file: TFile, fn: (current: string) => string): Promise<void>;
	adapter: VaultAdapter;
	on(name: string, cb: (...args: unknown[]) => unknown): { off: () => void };
}

export interface VaultAdapter {
	read(path: string): Promise<string>;
	write(path: string, content: string): Promise<void>;
	exists(path: string): Promise<boolean>;
}

export interface MetadataCache {
	getFileCache(file: TFile): CachedMetadata | null;
	getAllPropertyInfos?(): Record<string, { type: string }>;
	getTags?(): Record<string, number>;
	on(name: string, cb: (...args: unknown[]) => unknown): { off: () => void };
}

export interface FileManager {
	processFrontMatter(file: TFile, fn: (fm: Record<string, unknown>) => void): Promise<void>;
	renameFile(file: TFile, newPath: string): Promise<void>;
	trashFile(file: TFile): Promise<void>;
}

export interface Workspace {
	on(name: string, cb: (...args: unknown[]) => unknown): { off: () => void };
	getActiveFile(): TFile | null;
}

// ===== Pure helpers =====

export function getAllTags(meta: CachedMetadata | null | undefined): string[] | null {
	if (!meta) return null;
	const fm = meta.frontmatter ?? {};
	const out: string[] = [];
	const fmTags = fm.tags ?? fm.tag;
	if (Array.isArray(fmTags)) {
		for (const t of fmTags) out.push(`#${String(t).replace(/^#/, '')}`);
	} else if (typeof fmTags === 'string') {
		for (const t of fmTags.split(/[,\s]+/)) {
			if (t) out.push(`#${t.replace(/^#/, '')}`);
		}
	}
	for (const t of meta.tags ?? []) {
		out.push(t.tag.startsWith('#') ? t.tag : `#${t.tag}`);
	}
	return out;
}

export function prepareSimpleSearch(query: string) {
	const q = query.toLowerCase();
	return (text: string): { score: number } | null => {
		if (!q) return { score: 0 };
		return text.toLowerCase().includes(q) ? { score: 1 } : null;
	};
}

export function prepareFuzzySearch(query: string) {
	return prepareSimpleSearch(query);
}

export function setIcon(_el: HTMLElement, _name: string): void {
	// no-op for tests
}

export const parseYaml = parseYamlImpl;
export const stringifyYaml = stringifyYamlImpl;

// ===== Mock factories used by individual tests =====

export interface MockAppOptions {
	files?: TFile[];
	metadata?: Map<string, CachedMetadata>;
	folders?: TFolder[];
	configDir?: string;
	adapterFiles?: Map<string, string>;
}

export function mockTFile(
	path: string,
	options: { frontmatter?: Record<string, unknown> } = {},
): TFile {
	const file = new TFile();
	file.path = path;
	const segs = path.split('/');
	file.name = segs[segs.length - 1];
	const dot = file.name.lastIndexOf('.');
	file.extension = dot >= 0 ? file.name.slice(dot + 1) : '';
	file.basename = dot >= 0 ? file.name.slice(0, dot) : file.name;
	const parentPath = segs.slice(0, -1).join('/');
	if (parentPath) {
		const folder = new TFolder();
		folder.path = parentPath;
		folder.name = parentPath.split('/').pop() ?? '';
		file.parent = folder;
	}
	(file as TFile & { _frontmatter?: Record<string, unknown> })._frontmatter = options.frontmatter;
	return file;
}

export function mockTFolder(path: string): TFolder {
	const folder = new TFolder();
	folder.path = path;
	folder.name = path.split('/').pop() ?? '';
	return folder;
}

export function mockApp(opts: MockAppOptions = {}): App {
	const files = opts.files ?? [];
	const folders = opts.folders ?? [];
	const meta = opts.metadata ?? new Map<string, CachedMetadata>();
	const adapterFiles = opts.adapterFiles ?? new Map<string, string>();

	for (const f of files) {
		if (!meta.has(f.path)) {
			const fm = (f as TFile & { _frontmatter?: Record<string, unknown> })._frontmatter;
			if (fm) meta.set(f.path, { frontmatter: { ...fm } });
		}
	}

	const events = new Events();

	const vault: Vault = {
		configDir: opts.configDir ?? '.obsidian',
		getFiles: () => [...files],
		getMarkdownFiles: () => [...files],
		getFileByPath: (path) => files.find((f) => f.path === path) ?? null,
		getAbstractFileByPath: (path) =>
			files.find((f) => f.path === path) ?? folders.find((f) => f.path === path) ?? null,
		getAllFolders: () => [...folders],
		read: async (file) => adapterFiles.get(file.path) ?? '',
		modify: async (file, content) => {
			adapterFiles.set(file.path, content);
		},
		create: async (path, content) => {
			const f = mockTFile(path);
			files.push(f);
			adapterFiles.set(path, content);
			events.trigger('create', f);
			return f;
		},
		process: async (file, fn) => {
			const cur = adapterFiles.get(file.path) ?? '';
			adapterFiles.set(file.path, fn(cur));
		},
		adapter: {
			read: async (path) => {
				const v = adapterFiles.get(path);
				if (v == null) throw new Error(`ENOENT: ${path}`);
				return v;
			},
			write: async (path, content) => {
				adapterFiles.set(path, content);
			},
			exists: async (path) => adapterFiles.has(path),
		},
		on: (name, cb) => events.on(name, cb),
	};

	const metadataCache: MetadataCache = {
		getFileCache: (file) => meta.get(file.path) ?? null,
		on: (name, cb) => events.on(`meta:${name}`, cb),
	};

	const fileManager: FileManager = {
		processFrontMatter: async (file, fn) => {
			const cur = meta.get(file.path) ?? { frontmatter: {} };
			const fm = { ...cur.frontmatter };
			fn(fm);
			meta.set(file.path, { ...cur, frontmatter: fm });
		},
		renameFile: async (file, newPath) => {
			const old = file.path;
			file.path = newPath;
			file.name = newPath.split('/').pop() ?? '';
			file.basename = file.name.replace(/\.md$/, '');
			const m = meta.get(old);
			if (m) {
				meta.delete(old);
				meta.set(newPath, m);
			}
			const c = adapterFiles.get(old);
			if (c != null) {
				adapterFiles.delete(old);
				adapterFiles.set(newPath, c);
			}
		},
		trashFile: async (file) => {
			const idx = files.indexOf(file);
			if (idx >= 0) files.splice(idx, 1);
			meta.delete(file.path);
			adapterFiles.delete(file.path);
		},
	};

	const workspace: Workspace = {
		on: (name, cb) => events.on(`ws:${name}`, cb),
		getActiveFile: () => null,
	};

	return { vault, metadataCache, fileManager, workspace };
}

// Used by tests that mount Modals — attach a minimal HTMLElement-like surface
function makeEl(): HTMLElement {
	if (typeof document !== 'undefined') return document.createElement('div');
	const stub = {
		empty() {},
		addClass() {},
		removeClass() {},
		toggleClass() {},
		createEl(_tag: string, opts?: { text?: string; cls?: string }) {
			const child = makeEl();
			if (opts?.text) (child as unknown as { textContent: string }).textContent = opts.text;
			return child;
		},
		createDiv(opts?: { text?: string; cls?: string }) {
			const child = makeEl();
			if (opts?.text) (child as unknown as { textContent: string }).textContent = opts.text;
			return child;
		},
		createSpan(opts?: { text?: string }) {
			const child = makeEl();
			if (opts?.text) (child as unknown as { textContent: string }).textContent = opts.text;
			return child;
		},
		addEventListener() {},
		focus() {},
		setText() {},
		remove() {},
	};
	return stub as unknown as HTMLElement;
}

/**
 * Minimal Obsidian stub for vitest module resolution.
 * The real obsidian package has no runtime entry point (main: "").
 * Tests that use evalInObsidian run code inside the real Obsidian instance,
 * so these stubs only need to satisfy vitest's module resolver.
 */

export class TFile {
	path = '';
	name = '';
}

export class TFolder {
	path = '';
	name = '';
}

import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest';
import { flushSync, mount, unmount, type Component } from 'svelte';
import PanelExplorer from '../../src/components/containers/panelExplorer.svelte';
import { NodeSelectionService } from '../../src/services/serviceSelection.svelte';
import { ViewService } from '../../src/services/serviceViews.svelte';
import type { VaultmanPlugin } from '../../src/main';
import type { ExplorerProvider, ExplorerViewMode } from '../../src/types/typeExplorer';
import type { FileMeta, PropMeta, TreeNode } from '../../src/types/typeNode';
import type { IViewService } from '../../src/types/typeViews';
import { mockTFile } from '../helpers/obsidian-mocks';

const EXPLORER_ID = 'selection-test';

function nodes(): TreeNode[] {
	return [
		{ id: 'alpha', label: 'Alpha', depth: 0, meta: {}, icon: 'lucide-file' },
		{ id: 'beta', label: 'Beta', depth: 0, meta: {}, icon: 'lucide-file' },
	];
}

function nestedNodes(): TreeNode[] {
	return [
		{
			id: 'parent',
			label: 'Parent',
			depth: 0,
			meta: {},
			icon: 'lucide-folder',
			children: [{ id: 'child', label: 'Child', depth: 1, meta: {}, icon: 'lucide-file' }],
		},
		{ id: 'sibling', label: 'Sibling', depth: 0, meta: {}, icon: 'lucide-file' },
	];
}

function largeNestedNodes(): TreeNode[] {
	return [
		...nestedNodes(),
		...Array.from({ length: 8 }, (_, index) => ({
			id: `leaf-${index}`,
			label: `Leaf ${index}`,
			depth: 0,
			meta: {},
			icon: 'lucide-file',
		})),
	];
}

function manyFlatNodes(count = 40): TreeNode[] {
	return Array.from({ length: count }, (_, index) => ({
		id: `node-${index}`,
		label: `Node ${index}`,
		depth: 0,
		meta: {},
		icon: 'lucide-file',
	}));
}

function plugin(
	selectionService = new NodeSelectionService(),
	viewService: VaultmanPlugin['viewService'] = {
		clearSelection: vi.fn(),
		select: vi.fn(),
		setFocused: vi.fn(),
	} as unknown as VaultmanPlugin['viewService'],
): VaultmanPlugin {
	return {
		app: {},
		propertyIndex: { fileCount: 0 },
		operationsIndex: { nodes: [], subscribe: vi.fn(() => vi.fn()) },
		activeFiltersIndex: { subscribe: vi.fn(() => vi.fn()) },
		queueService: { remove: vi.fn(), requestDelete: vi.fn() },
		filterService: { setSelectedFiles: vi.fn() },
		viewService,
		selectionService,
	} as unknown as VaultmanPlugin;
}

function provider(overrides: Partial<ExplorerProvider> = {}): ExplorerProvider {
	return {
		id: EXPLORER_ID,
		getTree: vi.fn(() => nodes()),
		getFiles: vi.fn(() => []),
		handleNodeClick: vi.fn(),
		handleContextMenu: vi.fn(),
		...overrides,
	};
}

describe('PanelExplorer tree selection adapter', () => {
	let target: HTMLDivElement;
	let app: ReturnType<typeof mount> | null = null;

	beforeEach(() => {
		target = document.createElement('div');
		document.body.appendChild(target);
		vi.stubGlobal(
			'ResizeObserver',
			class {
				observe(): void {}
				disconnect(): void {}
			},
		);
	});

	afterEach(() => {
		if (app) {
			void unmount(app);
			app = null;
		}
		target.remove();
		vi.unstubAllGlobals();
	});

	function renderPanel(
		options: {
			selectionService?: NodeSelectionService;
			provider?: ExplorerProvider;
			viewMode?: ExplorerViewMode;
			gridHierarchyMode?: 'folder' | 'inline';
			nodeExpansionCommand?: unknown;
			onNodeExpansionSummaryChange?: (summary: unknown) => void;
		} = {},
	) {
		const selectionService = options.selectionService ?? new NodeSelectionService();
		const pluginStub = plugin(selectionService);
		pluginStub.settings = { ...pluginStub.settings, gridHierarchyMode: options.gridHierarchyMode };
		const providerStub = options.provider ?? provider();
		app = mount(PanelExplorer as unknown as Component<Record<string, unknown>>, {
			target,
			props: {
				plugin: pluginStub,
				provider: providerStub,
				viewMode: options.viewMode ?? 'tree',
				nodeExpansionCommand: options.nodeExpansionCommand,
				onNodeExpansionSummaryChange: options.onNodeExpansionSummaryChange,
				icon: vi.fn(() => ({ update: vi.fn() })),
			},
		});
		flushSync();
		return { pluginStub, providerStub, selectionService };
	}

	it('row-slot click selects through the node selection service without activating the node', () => {
		const { pluginStub, providerStub, selectionService } = renderPanel();

		(target.querySelector('[data-id="alpha"]') as HTMLElement).click();
		flushSync();

		expect([...selectionService.snapshot(EXPLORER_ID).ids]).toEqual(['alpha']);
		expect(pluginStub.viewService.clearSelection).toHaveBeenCalled();
		expect(pluginStub.viewService.select).toHaveBeenCalledWith(EXPLORER_ID, 'alpha', 'add');
		expect(pluginStub.viewService.setFocused).toHaveBeenCalledWith(EXPLORER_ID, 'alpha');
		expect(providerStub.handleNodeClick).not.toHaveBeenCalled();
	});

	it('label click selects without running the provider secondary action', () => {
		const { providerStub, selectionService } = renderPanel();

		(target.querySelector('[data-id="beta"] .vm-tree-label') as HTMLElement).click();
		flushSync();

		expect([...selectionService.snapshot(EXPLORER_ID).ids]).toEqual(['beta']);
		expect(providerStub.handleNodeClick).not.toHaveBeenCalled();
	});

	it('label double click runs the provider secondary action', () => {
		const { providerStub, selectionService } = renderPanel();
		const label = target.querySelector('[data-id="beta"] .vm-tree-label') as HTMLElement;

		label.click();
		label.click();
		flushSync();

		expect([...selectionService.snapshot(EXPLORER_ID).ids]).toEqual(['beta']);
		expect(providerStub.handleNodeClick).toHaveBeenCalledOnce();
		expect(providerStub.handleNodeClick).toHaveBeenCalledWith(
			expect.objectContaining({ id: 'beta' }),
		);
	});

	it('row surface double click runs the provider secondary action', () => {
		const { providerStub, selectionService } = renderPanel();
		const row = target.querySelector('[data-id="beta"]') as HTMLElement;

		row.click();
		row.click();
		flushSync();

		expect([...selectionService.snapshot(EXPLORER_ID).ids]).toEqual(['beta']);
		expect(providerStub.handleNodeClick).toHaveBeenCalledOnce();
		expect(providerStub.handleNodeClick).toHaveBeenCalledWith(
			expect.objectContaining({ id: 'beta' }),
		);
	});

	it('Alt click routes the node tertiary action through delete conflict handling', () => {
		const { pluginStub, providerStub, selectionService } = renderPanel({
			provider: provider({ handleHoverBadge: vi.fn() }),
		});

		(target.querySelector('[data-id="beta"] .vm-tree-label') as HTMLElement).dispatchEvent(
			new MouseEvent('click', { bubbles: true, altKey: true }),
		);
		flushSync();

		expect([...selectionService.snapshot(EXPLORER_ID).ids]).toEqual([]);
		expect(pluginStub.queueService.requestDelete).toHaveBeenCalledWith(
			expect.objectContaining({
				nodeId: 'beta',
				nodeLabel: 'Beta',
			}),
		);
		expect(providerStub.handleNodeClick).not.toHaveBeenCalled();
	});

	it('middle click routes the node tertiary action through delete conflict handling', () => {
		const { pluginStub, providerStub, selectionService } = renderPanel({
			provider: provider({ handleHoverBadge: vi.fn() }),
		});

		(target.querySelector('[data-id="beta"] .vm-tree-label') as HTMLElement).dispatchEvent(
			new MouseEvent('auxclick', { bubbles: true, cancelable: true, button: 1 }),
